#!/usr/bin/env node
/**
 * Отчёт по типичным местам в проекте-потребителе, которые мешают или
 * усложняют переход приложения на React 19.
*/

'use strict';

const fs = require('node:fs');
const path = require('node:path');

const EXTENSIONS = ['.js', '.jsx', '.ts', '.tsx'];
const DEFAULT_IGNORE_DIRS = ['node_modules', 'build', 'dist', '.git', 'coverage', '.next', 'out', '.cache'];

/** @type {{ id: string; re: RegExp; hint: string }[]} */
const CHECKS = [
	{
		id: 'react-dom-legacy-render',
		re: /\bReactDOM\.(render|hydrate)\s*\(/g,
		hint: 'Замените на createRoot / hydrateRoot из react-dom/client (см. react.dev upgrade guide).',
	},
	{
		id: 'react-dom-unmount',
		re: /\bunmountComponentAtNode\s*\(/g,
		hint: 'Используйте root.unmount() у экземпляра createRoot.',
	},
	{
		id: 'prop-types-fc',
		re: /^\s*[\w$]+\.(propTypes|defaultProps)\s*=/gm,
		hint: 'У функциональных компонентов используйте параметры по умолчанию вместо defaultProps на объекте компонента.',
	},
	{
		id: 'find-dom-node',
		re: /\bfindDOMNode\s*\(/g,
		hint: 'findDOMNode удалён; перепишите доступ к DOM.',
	},
];

function parseArgs(argv) {
	let ignoreExtra = [];
	for (let i = 2; i < argv.length; i++) {
		if (argv[i] === '--ignore' && argv[i + 1]) {
			ignoreExtra = argv[++i].split(',').map(s => s.trim()).filter(Boolean);
		}
	}
	return { ignoreDirs: [...DEFAULT_IGNORE_DIRS, ...ignoreExtra] };
}

function* walkFiles(rootDir, ignoreDirs) {
	const stack = [rootDir];
	while (stack.length) {
		const dir = stack.pop();
		let entries;
		try {
			entries = fs.readdirSync(dir, { withFileTypes: true });
		} catch {
			continue;
		}
		for (const e of entries) {
			const full = path.join(dir, e.name);
			const rel = path.relative(rootDir, full);
			if (e.isDirectory()) {
				if (!ignoreDirs.some(ign => rel.startsWith(ign) || e.name === ign)) stack.push(full);
			} else if (e.isFile() && EXTENSIONS.includes(path.extname(e.name))) {
				yield full;
			}
		}
	}
}

function scanFile(filePath) {
	const content = fs.readFileSync(filePath, 'utf8');
	const hits = [];
	for (const { id, re, hint } of CHECKS) {
		re.lastIndex = 0;
		let m;
		let line = 0;
		const lines = content.split('\n');
		while ((m = re.exec(content)) !== null) {
			const upto = content.slice(0, m.index);
			line = upto.split('\n').length;
			const lineText = lines[line - 1]?.trim() ?? '';
			hits.push({ id, line, hint, sample: lineText.slice(0, 120) });
		}
	}
	return hits;
}

function main() {
	const cwd = process.cwd();
	const { ignoreDirs } = parseArgs(process.argv);

	console.log('React 19 — отчёт по потенциальным проблемам в проекте');
	console.log(`Корень: ${cwd}`);
	console.log(`Игнор: ${ignoreDirs.join(', ')}\n`);

	let total = 0;
	for (const file of walkFiles(cwd, ignoreDirs)) {
		const hits = scanFile(file);
		if (!hits.length) continue;
		const rel = path.relative(cwd, file);
		console.log(`\n${rel}`);
		for (const h of hits) {
			total++;
			console.log(`  [${h.id}] строка ${h.line}: ${h.hint}`);
			if (h.sample) console.log(`    ${h.sample}`);
		}
	}

	if (total === 0) {
		console.log('\nЯвных совпадений по паттернам не найдено. Всё равно проверьте:');
		console.log('  - tsconfig / babel: jsx: "react-jsx"');
		console.log('  - версии react / react-dom и дубликаты (npm why react)');
		console.log('  - официальный codemod: npx codemod@latest react/19/migration-recipe');
	} else {
		console.log(`\nИтого совпадений: ${total}`);
	}
}

main();
